effect.shader:
float gradientNoise(in vec2 uv)
{
    const vec3 magic = vec3(0.06711056, 0.00583715, 52.9829189);
    return fract(magic.z * fract(dot(uv, magic.xy)));
}

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st = acLayerNorm;

    vec2 pos = (offset1*vec2(1,-1)) / 500.;
    float t1 = length(st - pos);

    pos = (offset2*vec2(1,-1)) / 500.;
    float t2 = length(st - pos);

    pos = (offset3*vec2(1,-1)) / 500.;
    float t3 = length(st - pos);

    pos = (offset4*vec2(1,-1)) / 500.;
    float t4 = length(st - pos);

    vec4 color = vec4(0.0, 0.0, 0.0, 0.0);
    float sw_t1 = smoothstep(0.0, 1.0, clamp((1.0 - t1), 0.0, 1.0));
    float sw_t2 = smoothstep(0.0, 1.0, clamp((1.0 - t2), 0.0, 1.0));
    float sw_t3 = smoothstep(0.0, 1.0, clamp((1.0 - t3), 0.0, 1.0));
    float sw_t4 = smoothstep(0.0, 1.0, clamp((1.0 - t4), 0.0, 1.0));
    color += color1 * pow(sw_t1, 1.0/blend);
    color += color2 * pow(sw_t2, 1.0/blend);
    color += color3 * pow(sw_t3, 1.0/blend);
    color += color4 * pow(sw_t4, 1.0/blend);
    color /= (sw_t1 + sw_t2 + sw_t3 + sw_t4);

    color.a = 1.0;
    color += (1.0/255.0) * gradientNoise(st) - (0.5/255.0);
    vec4 result;
    if( blendMode==1 ) {
        result = vec4((texColor.rgb/texColor.a)*color.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-color.rgb)),1.0) * texColor.a;
    } else {
        result = vec4(color.rgb,1.0)*texColor.a;
    }
    gl_FragColor = mix(texColor,result,alpha);
}
